/// <summary>
/// The ETGSalesEditLinesWorkflowTypeDocument workflow document class.
/// </summary>
class ETGSalesEditLinesWorkflowTypeDocument extends WorkflowDocument
{
    ETGSalesEditLines ETGSalesEditLines;
    SalesTable salesTable;

}

Method.Source:
    /// <summary>
	/// Returns query name for the workflow document.
	/// </summary>
	/// <returns>
	/// Name of the query <c>ETGSalesEditLinesQuery</c>.
	/// </returns>
	public queryName getQueryName()
	{
		return querystr(ETGSalesEditLinesQuery);
	}

public static ETGSalesEditLinesWorkflowTypeDocument construct()
{
    return new ETGSalesEditLinesWorkflowTypeDocument();
}

private ETGSalesEditLines getETGSaleseditLines(RecId  _recId)
{
    if (!ETGSalesEditLines)
    {
        ETGSalesEditLines = ETGSalesEditLines::findRecId(_recId);

    }

    return ETGSalesEditLines;
}

public InvoiceAmountMST parmInvoiceAmount(CompanyId _companyId, TableId _tableId, RecId _recId)
{
    InvoiceAmountMST amountMST;

    this.getETGSaleseditLines(_recId);

    if (ETGSalesEditLines)
    {
        amountMST = CurrencyExchangeHelper::amountCur2MST(ETGSalesEditLines.InvoiceAmount, salesTable.CurrencyCode);
    }

    return amountMST;
}

//CS Rajat Dubey 09/05/2025
public SalesIdBase parmSalesID(CompanyId _companyId, TableId _tableId, RecId _recId)
{
    SalesIdBase salesID;

    this.getETGSaleseditLines(_recId);

    if(ETGSalesEditLines)
    {
        salesID = ETGSalesEditLines.SalesId;
    }

    return salesID;
}
